import { client } from './axios-client';
import { buildAxiosRequestConfig } from './axios-utils';
import { axiosTrace as trace } from './axios-trace';
import { logRequestAndAnswser } from './log-request';
import axios from 'axios';

export async function axiosRequest(config: {
  method: string;
  url: string;
  headers?: any;
  data?: any;
}) {
  let response: any;
  try {
    const axiosConfig = buildAxiosRequestConfig(
      config.method,
      config.url,
      config.headers || {},
      config.data,
    );
    trace(axiosConfig);
    response = await client.request(axiosConfig);
    trace(response);
    logRequestAndAnswser(config.method, config.url, response);
  } catch (error) {
    if (axios.isAxiosError(error)) {
      response = error.response;
      trace(response);
      // Don't consider redirects as errors
      if (!response || response.status != 302) {
        throw new Error(error.message);
      } else {
        logRequestAndAnswser(config.method, config.url, response);
      }
    } else {
      trace((error as Error).message);
      throw new Error((error as Error).message);
    }
  }
  return response;
}
